var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":" 세상에, 재클린 경도 저렇게 맥없이 쓰러지다니……!","JPN":" そんな、ジャクリーン卿でさえあんなにあっけなく倒れるなんて……！","ENG":"Oh my, even Sir Jacques has fallen so easily...!","TWN":"哇，竟然連杰克林卿也敗陣下來……！"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":" 도전자들 중에 한 번이라도 공격을 버틴 사람이 없었어…….","JPN":" 挑戦者の中に一度でも攻撃に耐えた者がいなかった……","ENG":"None of the challengers have been able to withstand a single attack...","TWN":"挑戰者當中，完全沒有人可以抵擋攻勢……"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":" 역시 황태자 전하시다! 아르카데나 제국 최강의 무인이야!","JPN":" さすが皇太子殿下だ！　アルカデナ帝国最強の武人だ！","ENG":"Truly he is the Crown Prince! He is the greatest warrior in all of Arcadena!","TWN":"真不愧是皇太子殿下！艾爾卡特納帝國武功最強的人！"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":" 전하야말로 틀림없는 구원자시다! 마왕 네헤모트를 무찌르고 평화를 가져와 주실 게 틀림없어!","JPN":" 殿下こそ正真正銘の救世主だ！　魔王ネヘモトを打ち破り、平和をもたらしてくれるに違いない！","ENG":"There is no doubt that His Highness is the Savior! Surely he will defeat the Demon Lord Nehemoth and bring peace to the world!","TWN":"殿下才是真正的救贖者！殿下會打敗魔王 貝赫莫特帶來和平！"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":" 전하, 어째서 돌아오신 겁니까?","JPN":" 殿下、どうしてお戻りになったのですか？","ENG":"Your Highness, why have you returned?","TWN":"殿下怎麼回來了？"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 배우 노릇을 하는 것도 무료하더군. 잠시 쉬어야겠어.","JPN":" 俳優の真似もつまらないものだ。しばらく休むぞ。","ENG":"I grow weary of putting up a performance. I wish to rest for a while.","TWN":"演戲也是蠻累人的，我要休息一下。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":" 최후의 승자가 되려면 해가 지기 전까지 경기장을 지키고 있어야 합니다. 아시잖습니까.","JPN":" 最後の勝者になるためには日が暮れる前まで競技場を守らなければなりません。ご存じではありませんか。","ENG":"You must secure your place in the arena until the sun sets if you wish to be declared the final victor. Surely you know this.","TWN":"殿下應該也很清楚，要成為最後的贏家，就必須在日落前守住競技場。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 알렌 경도 관중들의 분위기를 느끼지 않았나?","JPN":" アレン卿も観衆の雰囲気を感じただろう。","ENG":"You must have also felt the atmosphere of the public, Sir Allen.","TWN":"艾倫卿不是也有感受到群眾的氛圍嗎？"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 저렇게 경도된 군중 앞에 나설 만한 인물은 그리 많지 않다. ","JPN":" あのように傾倒した群衆を前にして出られる人物はそうそう多くあるまい。 ","ENG":"Few can hope to stand in front of such a devoted crowd.","TWN":"在那樣的群眾壓力之下，還能站出來的人應該不多。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 그나마 재클린 경이 마지막이었지. 더 기다려 봤자 시간 낭비에 불과해.","JPN":" ジャクリーン卿が最後だったぞ。待っていても時間の無駄に過ぎん。","ENG":"Sir Jacques was probably the last of those who possessed that potential. Waiting any longer is a waste of time.","TWN":"杰克林卿應該是最後一個，再等下去也是浪費時間而已。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":" …….","JPN":" ……","ENG":"...","TWN":"……"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 마지막 승자가 성녀를 지명하고 성녀에게 구원자로 공인 받는단 말이지…….","JPN":" 最後の勝者が聖女を指名し、聖女から救世主として公認される、か……","ENG":"So, the final victor will appoint the Saintess and be officiated by the Saintess as the Savior...","TWN":"最後的贏家可以指定聖女人選，再由聖女承認為救贖者……"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 옛 일화를 맹목적으로 답습할 뿐인 참으로 고리타분한 절차 아닌가.","JPN":" 昔の逸話を盲目的に踏襲するだけの、まったく古くさい手続きではないか。","ENG":"Truly it is an old-fashioned procedure that blindly follows an old folktale.","TWN":"這不過就是承襲古老習俗的迂腐程序不是嗎？"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":" ……전하, 그 절차에 대해서입니디만.","JPN":" ……殿下、その手続きについてですが。","ENG":"Your Highness... about that procedure...","TWN":"……殿下，關於程序這件事。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 그래. 뻔한 내용 같지만, 어디 말해 보도록.","JPN":" ああ。わかりきった内容だと思うが、話してみろ。","ENG":"Yes. I already know where you are going with this, but ask away.","TWN":"說吧，雖然我知道你要說什麼，不過你還是說吧。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":" 정말 남쪽의 신전장을 성녀로 지명하실 겁니까?","JPN":" 本当に南方の神殿長を聖女に指名するおつもりですか？","ENG":"Do you seriously plan on appointing the Head Priestess of the South as the Saintess?","TWN":"殿下當真要指定南方的祭司長為聖女嗎？"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 그렇다. 구원자의 첫 행보가 배신한 성녀를 처단하는 것이면 꽤나 파격적일 테지.","JPN":" そうだ。救世主の第一歩が裏切った聖女の処断となれば、ずいぶんと型破りに見えるだろう。","ENG":"Correct. It will be a sight to see the Savior punish the traitorous Saintess as his first feat.","TWN":"沒錯，救贖者的第一步是要處決犯罪的聖女，這應該是很意外的展開吧。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 희극에서 비극으로 돌아서는 지점이니 관중들도 깊은 인상을 받을 것이다.","JPN":" 喜劇が悲劇に変わるわけだから、観衆も深い印象を受けるはずだ。","ENG":"As this will be the incident which turns triumph into tragedy, it will leave a lasting impression on the public.","TWN":"瞬間從喜劇轉成悲劇，觀眾們應該也會印象很深刻吧。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":" ……연극을 즐기시는 것은 이해하나, 그 한 번의 연출로 전하께서 괜한 정치적 부담을 짊어지시는 것이 아닐지 우려됩니다.","JPN":" ……芝居がお好きなことは承知しておりますが、その一度の演出で殿下が政治的に余計な負担をお抱えにならないか不安でございます。","ENG":"...I understand that you enjoy theater, but I am concerned that this one performance will force an avoidable political burden upon you, Your Highness.","TWN":"……我知道殿下喜歡看戲，但我擔心因為一次的演出，就會對殿下造成無謂的政治壓力。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 하하, 내게 정치를 논하다니 알렌 경. 그대도 이 제도에 꽤 익숙해졌나 보군.","JPN":" はは、私の前で政治を論ずるとはな、アレン卿。そなたもこの帝都にだいぶ慣れたようだな。","ENG":"Ha ha! To think that you would be discussing politics with me, Sir Allen. You finally seem to have familiarized yourself with this system.","TWN":"哈哈，艾倫卿，你竟然和我談政治，看來你也對這個體制適應不少囉？"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 허나 그것은 내 소관이다. 그대가 우려할 일이 아니지.","JPN":" だがそれは私の所管だ。そなたが心配することではあるまい。","ENG":"However, that is my jurisdiction. It is not something you should concern yourself with.","TWN":"不過那是我的事，你無須操心。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 그보다 경이 고향에서 데려왔다던 그 친척 소년은 어디에 있지?","JPN":" それより、卿が故郷から連れてきたという親戚の少年はどこにいる？","ENG":"More than that, where is the boy that you brought from your hometown?","TWN":"倒是你從家鄉帶上來的那個親戚人在哪？"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 경이 그토록 칭찬을 할 정도라면 필시 보통 실력은 아닐 테지. 아주 기대가 되네.","JPN":" 卿があれほど誉めるくらいだ、きっとただ者ではないのだろう。とても楽しみだ。","ENG":"Judging by how much you praise him, he must be of exceptional skill. I look very forward to meeting him.","TWN":"你那麼稱讚他，想必能力不在話下，我很期待呢。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":" 말씀드린 대로, 어제 잠시 자리를 비운 사이 행방이 묘연해졌습니다.","JPN":" 申し上げましたとおり、昨日しばらく席を外した際に行方がわからなくなりました。","ENG":"As I have mentioned, he has gone missing since yesterday after I left him by himself for a short while.","TWN":"先前也跟殿下稟告過，昨天我們暫時分開後，他便不知去向。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":" 근처에서 소동이 있었다고 하는데, 그 와중에 길을 잃었을지도 모르겠습니다.","JPN":" 近くで騒ぎがあったと聞きましたが、その渦中で道に迷ってしまったのかもしれません。","ENG":"I heard that there was a commotion nearby that area, so he may have gotten lost during that time.","TWN":"聽說昨天在附近有發生騷動，可能是在混亂之中不小心迷路。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":" 사람을 보내 수소문하도록 했으니 곧 소식이 있을 겁니다.","JPN":" 使いを出して探しておりますので、すぐに知らせがあるでしょう。","ENG":"I have sent someone to ask around, so I should be getting an update soon.","TWN":"我已派人去搜查，應該很快就會有消息。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 그런가? 출정식 전에 만났으면 좋았을 텐데 아쉽군.","JPN":" そうか？　出征式の前に会えたらよかったが、残念だな。","ENG":"Is that so? That’s a shame, I was hoping to meet him before the ceremony.","TWN":"是嗎？原本希望能在出征儀式前見到他的，真是可惜。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":" 이봐! 길을 비켜 줘!","JPN":" おい！　道を開けてやれ！","ENG":"Make way! Make way!","TWN":"喂！讓開！"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":" 도전하는 데 자격 같은 건 필요 없다지만…… 저런 애가 황태자 전하와 겨룰 수 있는 거 맞아? ","JPN":" 挑戦するのに資格なんていらないとはいっても……あんな子供が皇太子殿下と競い合えるのか？ ","ENG":"Although they say that no qualifications are required to participate, can a kid like that possibly hope to challenge the Crown Prince?","TWN":"雖說挑戰這種事是沒在論資格的……但那種小鬼和皇太子殿下較勁合適嗎？"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 음? 웬 소란이지?","JPN":" うむ？　何の騒ぎだ。","ENG":"Huh? What’s all this commotion about?","TWN":"嗯？在吵什麼？"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" ……호오. 알렌 경. 이번에는 내 예상이 조금 빗나갔군.","JPN":" ……ほう。アレン卿。今回は私の予想が少し外れたな。","ENG":"...Oh? Sir Allen, it seems that my predictions are off a bit this time.","TWN":"……呵，艾倫卿，看來這次有點出乎我的意料呢。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 더 이상의 도전자는 없을 줄 알았는데.","JPN":" もう挑戦者はいないだろうと思ったんだが。","ENG":"I thought that there would not be any other challengers.","TWN":"我還以為不會再有新的挑戰者。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":" 저건……. 설마?","JPN":" あれは……　もしや？","ENG":"Huh? Isn’t that...?","TWN":"那……該不會？"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 아직 앳된 나이로 보이는데…… 도전자로 나서다니 흥미로워.","JPN":" まだ幼く見えるが……挑戦者として出るとは興味深い。","ENG":"He still seems to be very young... It’s interesting that he decided to participate in the challenge.","TWN":"看起來年紀輕輕的……竟然以挑戰者之姿站上競技場，真有意思。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":" 아닙니다, 전하. 뭔가 착오가 있는 것 같습니다.","JPN":" 違います、殿下。何かの間違いかと。","ENG":"Your Highness, there seems to have been a mistake.","TWN":"不是的，殿下，當中應該有什麼誤會。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":" 저 소년은…….","JPN":" あの少年は……","ENG":"That boy is...","TWN":"他是……"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 참으로 담대하구나. 태도로 보아 황혼을 앞두고 온 것은 나름의 계략인가.","JPN":" なんて大胆なんだ。態度から察するに黄昏の直前に来たのは策があってのことだろう。","ENG":"I applaud your boldness, boy. Judging by your attitude, participating just before twilight seems to be a part of your plan.","TWN":"勇氣可嘉，看你的樣子，是刻意挑在太陽快要下山的時候嗎？"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 부디 그 용맹이 객기가 아니길 바라마.","JPN":" その勇猛が虚勢ではないことを願おう。","ENG":"I hope that your courage is not mere bravado.","TWN":"希望不是逞匹夫之勇。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":" 고하라! 도전자로서 경기장에 나선 그대의 이름은 무엇인가? ","JPN":" 告げよ！　挑戦者として競技場に出たそなたの名前を！ ","ENG":"See here! Challenger of this arena, what is thy name?","TWN":"場上的挑戰者，報上名來！"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":" ……레이. 평민이기에 성은 없습니다.","JPN":" ……レイ。平民なので名字はありません。","ENG":"...Ray. As I am a commoner, I have no family name.","TWN":"……雷伊，我是平民，所以沒有姓氏。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":" 멈춰, 레이! 저 분은 황태자 전하시다!","JPN":" 止まれ、レイ！　あの方は皇太子殿下だぞ！","ENG":"Stop, Ray! He is the Crown Prince!","TWN":"住手，雷伊！這位是皇太子殿下！"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RAY_KNIGHT_PAST_SWORD","text":{"KOREA":" 구원자의 자격을 걸고, 전하께 도전하겠습니다.","JPN":" 救世主の資格をかけて、殿下に挑みます。","ENG":"I challenge you for the title of the Savior, Your Highness.","TWN":"我要賭上救贖者的資格，挑戰殿下。"},"stage":{"bg":"COLOSSEUM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_KNIGHT_PAST_SWORD","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};